// SHARED STORAGE  (window.storage — all users share same data)
// ═══════════════════════════════════════════════════════════════
const K = {
  clients:"meca_clients", services:"meca_services", quotes:"meca_quotes",
  schedule:"meca_schedule", laudos:"meca_laudos", tecnicos:"meca_tecnicos",
  password:"meca_password"
};

async function load(key, fallback) {
  try {
    const r = await window.storage.get(key, true);
    return r ? JSON.parse(r.value) : fallback;
  } catch { return fallback; }
}

async function save(key, value) {
  try { await window.storage.set(key, JSON.stringify(value), true); } catch {}
}

