const DEFAULT_PW = "Meca@1010";
function uid() { return Date.now().toString(36) + Math.random().toString(36).slice(2, 6); }
function fmt(n) { return Number(n || 0).toLocaleString("pt-BR", { minimumFractionDigits: 2 }); }
function parseBR(s) { return Number(String(s || "0").replace(/\./g, "").replace(",", ".")) || 0; }
function fullAddr(c) {
  const parts = [];
  if (c.address) parts.push(c.address);
  const cu = c.city ? (c.uf ? c.city + "/" + c.uf : c.city) : c.uf || "";
  if (cu) parts.push(cu);
  return parts.join(", ");
}

