function Alert({msg}) {
  if (!msg) return null;
  const ok = msg.type === "success";
  return <div style={{padding:"10px 16px",borderRadius:7,fontSize:13,fontWeight:600,marginBottom:16,
    background:ok?"rgba(39,174,96,0.15)":"rgba(192,57,43,0.15)",
    color:ok?"#2ecc71":"#e74c3c",border:"1px solid "+(ok?"#2ecc7133":"#e74c3c33")}}>{msg.text}</div>;
}

function Modal({title, onClose, children, maxWidth=640}) {
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.78)",display:"flex",
      alignItems:"center",justifyContent:"center",zIndex:1000,padding:16,overflowY:"auto"}}
      onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{background:C.navyM,borderRadius:14,border:"1px solid "+C.border,
        width:"100%",maxWidth,padding:24,boxShadow:"0 24px 64px rgba(0,0,0,0.65)",
        margin:"auto"}}>
        <div style={{...row,justifyContent:"space-between",marginBottom:20}}>
          <span style={{fontSize:17,fontWeight:800,color:C.orange}}>{title}</span>
          <button style={btn("ghost")} onClick={onClose}><Icon d={IC.x} size={16}/></button>
        </div>
        {children}
      </div>
    </div>
  );
}

function Section({icon, children}) {
  return <div style={{fontSize:15,fontWeight:700,color:C.orange,marginBottom:14,display:"flex",alignItems:"center",gap:8}}>
    <Icon d={icon} size={16}/>{children}
  </div>;
}

function DocPreview({html, title, onClose}) {
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.88)",display:"flex",
      flexDirection:"column",zIndex:2000}}>
      <div style={{background:"#0f1f38",borderBottom:"2px solid "+C.orange,padding:"12px 20px",
        display:"flex",alignItems:"center",justifyContent:"space-between",flexShrink:0}}>
        <span style={{fontWeight:700,fontSize:15,color:C.orange}}>{title}</span>
        <div style={row}>
          <span style={{fontSize:12,color:C.blueL}}>Ctrl+P para salvar PDF</span>
          <button onClick={onClose} style={{...btn("danger"),padding:"7px 14px"}}>✕ Fechar</button>
        </div>
      </div>
      <div style={{flex:1,overflow:"auto",background:"#fff"}}>
        <iframe srcDoc={html} style={{width:"100%",height:"100%",border:"none"}} title={title}/>
      </div>
    </div>
  );
}

