    ".logo{width:64px;height:64px;object-fit:cover;border-radius:6px}",
    ".bn{font-size:26px;font-weight:900;color:#e8670a;letter-spacing:-1px}",
    ".bs{font-size:11px;color:#666;letter-spacing:2px;text-transform:uppercase}",
    "h2{font-size:13px;color:#e8670a;margin:16px 0 8px;text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid #eee;padding-bottom:4px}",
    ".ig{display:grid;grid-template-columns:1fr 1fr;gap:8px 24px;margin-bottom:16px}",
    ".ii label{font-size:10px;color:#888;text-transform:uppercase;letter-spacing:1px;display:block;margin-bottom:1px}",
    ".ii span{font-size:13px;color:#111;font-weight:600}",
