    "th{background:#f5f5f5;text-align:left;padding:8px 10px;font-size:11px;color:#555;text-transform:uppercase;border-bottom:2px solid #ddd}",
    "td{padding:9px 10px;border-bottom:1px solid #eee;font-size:13px}",
    ".tb{text-align:right;margin-top:14px;padding-top:12px;border-top:2px solid #e8670a}",
    ".tl{font-size:11px;color:#888;text-transform:uppercase;letter-spacing:1px}",
    ".tv{font-size:26px;font-weight:900;color:#e8670a}",
    ".cond{display:grid;grid-template-columns:1fr 1fr;gap:8px 24px;margin:14px 0;padding:12px;background:#f9f9f9;border-radius:6px;border:1px solid #eee}",
