    ".foot{margin-top:40px;text-align:center;font-size:10px;color:#aaa;border-top:1px solid #eee;padding-top:12px}",
    ".sg{display:grid;grid-template-columns:1fr 1fr;gap:32px;margin-top:40px;padding:20px;border:1px solid #ddd;border-radius:6px}",
