// SIGNATURE MODAL
// ═══════════════════════════════════════════════════════════════
function SignatureModal({onSave, onClose, initNome=""}) {
  const ref = useRef(null);
  const drawing = useRef(false);
  const last = useRef(null);
  const [hasSig, setHasSig] = useState(false);
  const [nome, setNome] = useState(initNome);
  const [doc, setDoc] = useState("");
  const [err, setErr] = useState("");

  function pos(e) {
    const c = ref.current; if (!c) return null;
    const r = c.getBoundingClientRect();
    const s = e.touches ? e.touches[0] : e;
    return {x:(s.clientX-r.left)*(c.width/r.width), y:(s.clientY-r.top)*(c.height/r.height)};
  }
  function down(e) { e.preventDefault(); drawing.current=true; const p=pos(e); if(!p)return; last.current=p; const ctx=ref.current.getContext("2d"); ctx.beginPath(); ctx.arc(p.x,p.y,2,0,Math.PI*2); ctx.fillStyle="#0a2a6e"; ctx.fill(); }
  function move(e) { e.preventDefault(); if(!drawing.current||!last.current)return; const p=pos(e); if(!p)return; const ctx=ref.current.getContext("2d"); ctx.beginPath(); ctx.moveTo(last.current.x,last.current.y); ctx.lineTo(p.x,p.y); ctx.strokeStyle="#0a2a6e"; ctx.lineWidth=3; ctx.lineCap="round"; ctx.stroke(); last.current=p; setHasSig(true); }
  function up(e) { e.preventDefault(); drawing.current=false; last.current=null; }
  function clear() { if(!ref.current)return; ref.current.getContext("2d").clearRect(0,0,640,200); setHasSig(false); }
  function confirm() {
    if (!nome.trim()) { setErr("Informe o nome do signatário."); return; }
    if (!hasSig) { setErr("Assine no campo abaixo."); return; }
    onSave({sigData:ref.current.toDataURL(), sigNome:nome.trim(), sigDoc:doc.trim()});
  }

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.95)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:4000,padding:16}}>
      <div style={{background:C.navyM,borderRadius:16,border:"1px solid "+C.border,width:"100%",maxWidth:680,padding:24}}>
        <div style={{...row,justifyContent:"space-between",marginBottom:18}}>
          <span style={{fontSize:17,fontWeight:800,color:C.orange}}>✍️ Assinatura do Cliente</span>
          <button style={btn("ghost")} onClick={onClose}><Icon d={IC.x} size={18}/></button>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:16}}>
          <div style={fld}><label style={lbl}>Nome Completo *</label>
            <input style={inp} value={nome} onChange={e=>{setNome(e.target.value);setErr("");}} placeholder="Nome"/></div>
          <div style={fld}><label style={lbl}>CPF / RG / Documento</label>
            <input style={inp} value={doc} onChange={e=>setDoc(e.target.value)} placeholder="000.000.000-00"/></div>
        </div>
        <label style={{...lbl,display:"block",marginBottom:8}}>Assinatura *</label>
        <div style={{position:"relative",background:"#fff",borderRadius:10,border:"3px solid "+C.blue}}>
          <canvas ref={ref} width={640} height={200}
            style={{display:"block",width:"100%",height:200,cursor:"crosshair",touchAction:"none"}}
            onMouseDown={down} onMouseMove={move} onMouseUp={up} onMouseLeave={up}
            onTouchStart={down} onTouchMove={move} onTouchEnd={up}/>
          {!hasSig&&<div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",pointerEvents:"none",color:"#bbb",fontSize:16,fontStyle:"italic"}}>Assine aqui com o dedo ou mouse</div>}
        </div>
        {err&&<div style={{marginTop:10,padding:"8px 14px",borderRadius:7,fontSize:13,fontWeight:600,background:"rgba(192,57,43,0.15)",color:"#e74c3c"}}>{err}</div>}
        <div style={{...row,justifyContent:"space-between",marginTop:18}}>
          <button style={{...btn("ghost"),padding:"10px 18px"}} onClick={clear}><Icon d={IC.trash} size={15}/>Limpar</button>
          <div style={row}>
            <button style={{...btn("ghost"),padding:"10px 18px"}} onClick={onClose}>Cancelar</button>
            <button style={{...btn("primary"),padding:"10px 22px"}} onClick={confirm}><Icon d={IC.check} size={15}/>Confirmar</button>
          </div>
        </div>
      </div>
    </div>
  );
}

