function TabOrcamento({clients, services, data, onSave, onDelete}) {
  const [form, setForm] = useState(emptyQ);
  const [view, setView] = useState("form");
  const [cp, setCP] = useState(false);
  const [sp, setSP] = useState(null);
  const [sel, setSel] = useState(null);
  const [preview, setPreview] = useState(null);
  const [msg, setMsg] = useState(null);
  const flash = (t,tp="success")=>{setMsg({text:t,type:tp});setTimeout(()=>setMsg(null),3000);};

  const sf = k=>e=>setForm(f=>({...f,[k]:e.target.value}));
  const si = (idx,k,v)=>setForm(f=>({...f,items:f.items.map((it,i)=>i===idx?{...it,[k]:v}:it)}));
  const addI = ()=>setForm(f=>({...f,items:[...f.items,{id:uid(),desc:"",unit:"und",qty:"1",price:""}]}));
  const remI = idx=>setForm(f=>({...f,items:f.items.filter((_,i)=>i!==idx)}));
  const pickSvc = (idx,s)=>{setForm(f=>({...f,items:f.items.map((it,i)=>i===idx?{...it,desc:s.name,unit:s.unit,price:s.price}:it)}));setSP(null);};
  const selClient = c=>{setSel(c);setForm(f=>({...f,clientName:c.name,clientDoc:c.doc,clientPhone:c.phone||"",clientAddress:c.address||"",clientCity:c.city+(c.uf?"/"+c.uf:"")}));setCP(false);};
  const clrClient = ()=>{setSel(null);setForm(f=>({...f,clientName:"",clientDoc:"",clientPhone:"",clientAddress:"",clientCity:""}));};
  const total = form.items.reduce((s,it)=>s+parseBR(it.price)*Number(it.qty||0),0);

  const saveQ = ()=>{
    if (!form.clientName.trim()){flash("Informe o cliente.","error");return;}
    if (!form.items.some(it=>it.desc.trim())){flash("Adicione ao menos um serviço.","error");return;}
    const e={...form,id:uid(),total,date:new Date().toLocaleDateString("pt-BR")};
    onSave(e);setSel(null);setForm(emptyQ());setView("list");flash("Orçamento salvo!");
  };

  const APPT_STATUS={agendado:"Agendado",confirmado:"Confirmado",concluido:"Concluído",cancelado:"Cancelado"};

  return <div><Alert msg={msg}/>
    <div style={{...row,marginBottom:18,gap:8}}>
      <button style={btn(view==="form"?"primary":"ghost")} onClick={()=>setView("form")}><Icon d={IC.quote} size={14}/>Novo</button>
      <button style={btn(view==="list"?"primary":"ghost")} onClick={()=>setView("list")}><Icon d={IC.list} size={14}/>Salvos ({data.length})</button>
    </div>

    {view==="form"&&<>
      <div style={card}>
        <Section icon={IC.user}>Dados do Cliente</Section>
        <div style={{...row,marginBottom:14,flexWrap:"wrap"}}>
          {sel?<><span style={{background:"rgba(232,103,10,0.15)",color:C.orange,border:"1px solid #e8670a44",borderRadius:20,padding:"3px 14px",fontSize:12,fontWeight:700}}>✓ {sel.name}</span>
              <button style={btn("ghost")} onClick={clrClient}><Icon d={IC.x} size={13}/>Remover</button></>
            :<button style={btn("blue")} onClick={()=>setCP(true)}><Icon d={IC.users} size={14}/>Selecionar Cadastrado</button>}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          {[["clientName","Nome / Razão Social"],["clientDoc","CNPJ / CPF"],["clientPhone","Telefone"],["clientCity","Cidade/UF"]].map(([k,l])=>
            <div key={k} style={fld}><label style={lbl}>{l}</label><input style={inp} value={form[k]} onChange={sf(k)}/></div>)}
          <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Endereço</label><input style={inp} value={form.clientAddress} onChange={sf("clientAddress")} placeholder="Rua, nº, bairro"/></div>
        </div>
      </div>

      <div style={card}>
        <Section icon={IC.wrench}>Serviços</Section>
        {form.items.map((item,idx)=><div key={item.id} style={{background:C.navy,border:"1px solid "+C.border,borderRadius:8,padding:"14px",marginBottom:10}}>
          <div style={{display:"flex",gap:8,marginBottom:10,alignItems:"flex-start"}}>
            <div style={{...fld,flex:1}}><label style={lbl}>Descrição</label>
              <textarea rows={2} style={{...inp,resize:"vertical",minHeight:48}} value={item.desc} placeholder="Descreva o serviço…" onChange={e=>si(idx,"desc",e.target.value)}/></div>
            <div style={{paddingTop:18}}><button style={{...btn("blue"),padding:"9px 12px"}} onClick={()=>setSP(idx)}><Icon d={IC.search} size={14}/>Catálogo</button></div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"130px 100px 1fr 40px",gap:10,alignItems:"end"}}>
            <div style={fld}><label style={lbl}>Unidade</label>
              <select style={inp} value={item.unit} onChange={e=>si(idx,"unit",e.target.value)}>{["und","hr","m²","m","kg","pc","vb"].map(u=><option key={u}>{u}</option>)}</select></div>
            <div style={fld}><label style={lbl}>Qtd</label><input type="number" min={0} style={inp} value={item.qty} onChange={e=>si(idx,"qty",e.target.value)}/></div>
            <div style={fld}><label style={lbl}>Valor Unit. (R$)</label><input style={inp} value={item.price} placeholder="0,00" onChange={e=>si(idx,"price",e.target.value)}/></div>
            <button style={{...btn("danger"),padding:"9px 10px"}} onClick={()=>remI(idx)} disabled={form.items.length===1}><Icon d={IC.trash} size={14}/></button>
          </div>
          {parseBR(item.price)>0&&Number(item.qty)>0&&<div style={{textAlign:"right",marginTop:8,fontSize:12,color:C.muted}}>Subtotal: <span style={{color:C.orange,fontWeight:700}}>R$ {fmt(parseBR(item.price)*Number(item.qty))}</span></div>}
        </div>)}
        <button style={{...btn("ghost"),marginTop:4}} onClick={addI}><Icon d={IC.plus} size={14}/>Adicionar linha</button>
        <div style={{height:1,background:C.border,margin:"18px 0"}}/>
        <div style={{display:"flex",justifyContent:"flex-end",alignItems:"center",gap:14}}>
          <span style={{fontSize:13,color:C.muted}}>Total estimado:</span>
          <span style={{fontSize:28,fontWeight:800,color:C.orange}}>R$ {fmt(total)}</span>
        </div>
      </div>

      <div style={card}>
        <Section icon={IC.tag}>Condições Comerciais</Section>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
          <div style={fld}><label style={lbl}>Prazo</label><input style={inp} value={form.prazo} onChange={sf("prazo")} placeholder="Ex: 5 dias úteis"/></div>
          <div style={fld}><label style={lbl}>Validade (dias)</label><input type="number" min={1} style={inp} value={form.validade} onChange={sf("validade")}/></div>
          <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Pagamento</label><input style={inp} value={form.pagamento} onChange={sf("pagamento")} placeholder="Ex: 50% entrada + 50% entrega"/></div>
          <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Garantia</label><input style={inp} value={form.garantia} onChange={sf("garantia")} placeholder="Ex: 90 dias"/></div>
          <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Observações</label><textarea style={{...inp,resize:"vertical",minHeight:64}} value={form.obs} onChange={sf("obs")}/></div>
        </div>
      </div>
      <div style={{display:"flex",justifyContent:"flex-end",marginBottom:28}}>
        <button style={{...btn("primary"),padding:"12px 30px",fontSize:15}} onClick={saveQ}><Icon d={IC.save} size={16}/>Salvar Orçamento</button>
      </div>
    </>}

    {view==="list"&&<div>
      {data.length===0?<div style={{...card,textAlign:"center",padding:48,color:"#3a5880"}}>Nenhum orçamento salvo.</div>
        :data.map(q=><div key={q.id} style={{...card}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14,flexWrap:"wrap",gap:10}}>
            <div>
              <div style={{fontSize:16,fontWeight:800}}>{q.clientName}</div>
              <div style={{fontSize:12,color:C.blueL,marginTop:2}}>{q.clientDoc&&<span style={{marginRight:10}}>{q.clientDoc}</span>}{q.clientCity&&<span>📍 {q.clientCity}</span>}</div>
            </div>
            <div style={{...row,flexWrap:"wrap",gap:8}}>
              <span style={{fontSize:12,color:C.muted}}>{q.date}</span>
              <button style={{...btn("blue"),padding:"6px 12px",fontSize:12}} onClick={()=>setPreview({html:buildQuoteDoc(q,clients),title:"Orçamento – "+q.clientName})}><Icon d={IC.down} size={13}/>PDF</button>
              <button style={{background:"#25D366",border:"none",borderRadius:7,padding:"6px 12px",fontSize:12,fontWeight:700,color:"#fff",cursor:"pointer"}} onClick={()=>openWA(waText("ORÇAMENTO",[`*Cliente:* ${q.clientName}`,q.clientPhone?`*Tel:* ${q.clientPhone}`:"",q.clientAddress?`*End:* ${q.clientAddress}`:"","",`*SERVIÇOS:*`,...(q.items||[]).filter(i=>i.desc).map((it,i)=>`${i+1}. ${it.desc} (${it.qty} ${it.unit}) - R$ ${fmt(parseBR(it.price)*Number(it.qty||0))}`),``,`*TOTAL: R$ ${fmt(q.total)}*`,q.prazo?`*Prazo:* ${q.prazo}`:"",q.pagamento?`*Pagamento:* ${q.pagamento}`:"",q.garantia?`*Garantia:* ${q.garantia}`:""].filter(Boolean)),q.clientPhone)}>📲 WhatsApp</button>
              <button style={{...btn("danger"),padding:"6px 10px"}} onClick={()=>{if(window.confirm("Excluir?"))onDelete(q.id);}}><Icon d={IC.trash} size={14}/></button>
            </div>
          </div>
          <table style={{width:"100%",borderCollapse:"collapse",marginBottom:12}}>
            <thead><tr style={{background:C.navy}}>{["Descrição","Unid.","Qtd","Valor Unit.","Subtotal"].map(h=><th key={h} style={{textAlign:"left",padding:"8px 12px",fontSize:11,color:C.blueL,letterSpacing:1,textTransform:"uppercase",borderBottom:"1px solid "+C.border}}>{h}</th>)}</tr></thead>
            <tbody>{(q.items||[]).filter(it=>it.desc&&it.desc.trim()).map((it,i)=>{const sub=parseBR(it.price)*Number(it.qty||0);return <tr key={i}>
              <td style={{padding:"10px 12px",borderBottom:"1px solid "+C.navyL}}>{it.desc}</td>
              <td style={{padding:"10px 12px",borderBottom:"1px solid "+C.navyL,fontSize:12,color:C.blueL}}>{it.unit}</td>
              <td style={{padding:"10px 12px",borderBottom:"1px solid "+C.navyL}}>{it.qty}</td>
              <td style={{padding:"10px 12px",borderBottom:"1px solid "+C.navyL}}>R$ {it.price||"0,00"}</td>
              <td style={{padding:"10px 12px",borderBottom:"1px solid "+C.navyL,fontWeight:700}}>R$ {fmt(sub)}</td>
            </tr>;})}
            </tbody>
          </table>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end",flexWrap:"wrap",gap:12}}>
            <div style={{display:"flex",gap:20,flexWrap:"wrap"}}>
              {q.prazo&&<div><div style={{...lbl,marginBottom:2}}>Prazo</div><div style={{fontSize:13}}>{q.prazo}</div></div>}
              {q.pagamento&&<div><div style={{...lbl,marginBottom:2}}>Pagamento</div><div style={{fontSize:13}}>{q.pagamento}</div></div>}
              {q.garantia&&<div><div style={{...lbl,marginBottom:2}}>Garantia</div><div style={{fontSize:13}}>{q.garantia}</div></div>}
            </div>
            <div style={{textAlign:"right"}}><div style={{fontSize:11,color:C.muted,textTransform:"uppercase",letterSpacing:1}}>Total</div><div style={{fontSize:24,fontWeight:800,color:C.orange}}>R$ {fmt(q.total)}</div></div>
          </div>
          {q.obs&&<div style={{marginTop:10,fontSize:12,color:C.muted,fontStyle:"italic",borderTop:"1px solid "+C.border,paddingTop:10}}>{q.obs}</div>}
        </div>)}
    </div>}

    {cp&&<ClientPicker clients={clients} onSelect={selClient} onClose={()=>setCP(false)}/>}
    {sp!==null&&<ServicePicker services={services} onSelect={s=>pickSvc(sp,s)} onClose={()=>setSP(null)}/>}
    {preview&&<DocPreview html={preview.html} title={preview.title} onClose={()=>setPreview(null)}/>}
  </div>;
}


// ═══════════════════════════════════════════════════════════════
// TAB: AGENDAMENTO
// ═══════════════════════════════════════════════════════════════
const APST = {agendado:{label:"Agendado",color:"#1a6fb5",bg:"rgba(26,111,181,0.15)"},confirmado:{label:"Confirmado",color:"#2ecc71",bg:"rgba(46,204,113,0.15)"},concluido:{label:"Concluído",color:"#27ae60",bg:"rgba(39,174,96,0.15)"},cancelado:{label:"Cancelado",color:"#e74c3c",bg:"rgba(231,76,60,0.15)"}};
function ABadge({status}){const s=APST[status]||{label:status,color:"#888",bg:"rgba(128,128,128,0.1)"};return <span style={{background:s.bg,color:s.color,border:"1px solid "+s.color+"44",borderRadius:20,padding:"3px 12px",fontSize:11,fontWeight:700}}>{s.label}</span>;}

function ApptModal({initial, clients, tecnicos, onSave, onClose}) {
  const [f, setF] = useState(initial?{...initial}:{id:"",clientId:"",clientName:"",clientPhone:"",clientAddress:"",clientCity:"",date:"",time:"",techName:"",serviceDesc:"",status:"agendado",notes:""});
  const [cp, setCP] = useState(false);
  const s = k=>e=>setF(p=>({...p,[k]:e.target.value}));
  const selC = c=>{setF(p=>({...p,clientId:c.id,clientName:c.name,clientPhone:c.phone||"",clientAddress:c.address||"",clientCity:c.city+(c.uf?"/"+c.uf:"")}));setCP(false);};
  const activeTec = (tecnicos||[]).filter(t=>t.active);

  return <Modal title={f.id?"Editar Agendamento":"Novo Agendamento"} onClose={onClose} maxWidth={560}>
    {cp&&<ClientPicker clients={clients} onSelect={selC} onClose={()=>setCP(false)}/>}
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Cliente</label>
        <div style={{display:"flex",gap:8}}><input style={{...inp,flex:1}} value={f.clientName} onChange={s("clientName")} placeholder="Nome"/>
          <button style={{...btn("blue"),padding:"9px 12px",flexShrink:0}} onClick={()=>setCP(true)}><Icon d={IC.users} size={14}/>Buscar</button></div></div>
      <div style={fld}><label style={lbl}>Telefone</label><input style={inp} value={f.clientPhone} onChange={s("clientPhone")}/></div>
      <div style={fld}><label style={lbl}>Cidade/UF</label><input style={inp} value={f.clientCity} onChange={s("clientCity")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Endereço</label><input style={inp} value={f.clientAddress} onChange={s("clientAddress")} placeholder="Rua, nº, bairro"/></div>
      <div style={fld}><label style={lbl}>Data</label><input type="date" style={inp} value={f.date} onChange={s("date")}/></div>
      <div style={fld}><label style={lbl}>Horário</label><input type="time" style={inp} value={f.time} onChange={s("time")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Técnico</label>
        {activeTec.length>0
          ?<select style={inp} value={f.techName} onChange={s("techName")}>
              <option value="">— Selecionar —</option>
              {activeTec.map(t=><option key={t.id} value={t.name}>{t.name}{t.specialty?" · "+t.specialty:""}</option>)}
              <option value="__outro__">Outro…</option>
            </select>
          :<input style={inp} value={f.techName} onChange={s("techName")} placeholder="Nome do técnico"/>}
        {f.techName==="__outro__"&&<input style={{...inp,marginTop:8}} autoFocus placeholder="Nome do técnico" onChange={e=>setF(p=>({...p,techName:e.target.value}))}/>}
      </div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Descrição do Serviço</label><textarea rows={3} style={{...inp,resize:"vertical",minHeight:72}} value={f.serviceDesc} onChange={s("serviceDesc")}/></div>
      <div style={fld}><label style={lbl}>Status</label>
        <select style={inp} value={f.status} onChange={s("status")}>{Object.entries(APST).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}</select></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Observações</label><textarea style={{...inp,resize:"vertical",minHeight:52}} value={f.notes} onChange={s("notes")}/></div>
    </div>
    <div style={{...row,justifyContent:"flex-end",marginTop:18,gap:10}}>
      <button style={btn("ghost")} onClick={onClose}>Cancelar</button>
      <button style={btn("primary")} onClick={()=>{if(!f.clientName||!f.date){alert("Informe cliente e data.");return;}onSave({...f,id:f.id||uid()});}}><Icon d={IC.save} size={15}/>Salvar</button>
    </div>
  </Modal>;
}

function TabAgendamento({clients, tecnicos, data, onSave, onDelete, onChange}) {
  const [modal, setModal] = useState(null);
  const [filter, setFilter] = useState("todos");
  const [search, setSearch] = useState("");
  const [preview, setPreview] = useState(null);
  const [msg, setMsg] = useState(null);
  const flash = (t,tp="success")=>{setMsg({text:t,type:tp});setTimeout(()=>setMsg(null),3000);};

  const filtered = data.filter(a=>{
    const ms = filter==="todos"||a.status===filter;
    const q = search.toLowerCase();
    const mq = !q||[a.clientName,a.techName,a.serviceDesc].some(v=>(v||"").toLowerCase().includes(q));
    return ms&&mq;
  }).sort((a,b)=>(a.date+a.time)>(b.date+b.time)?1:-1);

  const counts = data.reduce((acc,a)=>{acc[a.status]=(acc[a.status]||0)+1;return acc;},{});

  return <div><Alert msg={msg}/>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:18}}>
      {Object.entries(APST).map(([k,v])=><div key={k} style={{background:C.navyM,border:"1px solid "+C.border,borderRadius:10,padding:"14px 18px",borderLeft:"3px solid "+v.color,cursor:"pointer",opacity:filter===k||filter==="todos"?1:0.5}} onClick={()=>setFilter(filter===k?"todos":k)}>
        <div style={{fontSize:22,fontWeight:800,color:v.color}}>{counts[k]||0}</div>
        <div style={{fontSize:12,color:C.muted,marginTop:2}}>{v.label}</div>
      </div>)}
    </div>
    <div style={{...row,justifyContent:"space-between",marginBottom:14,flexWrap:"wrap",gap:10}}>
      <input placeholder="Buscar…" value={search} onChange={e=>setSearch(e.target.value)} style={{...inp,maxWidth:360}}/>
      <div style={row}>
        <select style={{...inp,width:"auto"}} value={filter} onChange={e=>setFilter(e.target.value)}>
          <option value="todos">Todos</option>{Object.entries(APST).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
        </select>
        <button style={btn("primary")} onClick={()=>setModal("new")}><Icon d={IC.plus} size={15}/>Novo</button>
      </div>
    </div>
    {filtered.length===0?<div style={{...card,textAlign:"center",padding:48,color:"#3a5880"}}>{data.length===0?"Nenhum agendamento.":"Sem resultados."}</div>
      :<div style={{display:"flex",flexDirection:"column",gap:10}}>
        {filtered.map(a=>{
          const cl=(clients||[]).find(c=>c.name===a.clientName||(a.clientId&&c.id===a.clientId));
          const addr=a.clientAddress||(cl?fullAddr(cl):"");
          return <div key={a.id} style={{background:C.navyM,border:"1px solid "+C.border,borderRadius:12,padding:"14px 18px",display:"grid",gridTemplateColumns:"80px 1fr auto",gap:14,alignItems:"center",borderLeft:"4px solid "+(APST[a.status]?.color||C.border)}}>
            <div style={{textAlign:"center"}}>
              <div style={{fontSize:20,fontWeight:800,color:C.orange,lineHeight:1}}>{a.date?a.date.slice(8):"—"}</div>
              <div style={{fontSize:11,color:C.muted,marginTop:2}}>{a.date?new Date(a.date+"T12:00:00").toLocaleDateString("pt-BR",{month:"short",year:"2-digit"}):""}</div>
              {a.time&&<div style={{fontSize:13,color:C.blueL,marginTop:3,fontWeight:700}}>{a.time}</div>}
            </div>
            <div>
              <div style={{...row,marginBottom:4,flexWrap:"wrap"}}><span style={{fontWeight:800,fontSize:14}}>{a.clientName}</span><ABadge status={a.status}/></div>
              {a.serviceDesc&&<div style={{fontSize:13,marginBottom:3}}>{a.serviceDesc}</div>}
              <div style={{display:"flex",gap:14,flexWrap:"wrap"}}>
                {a.techName&&<span style={{fontSize:12,color:C.blueL}}>👷 {a.techName}</span>}
                {a.clientPhone&&<span style={{fontSize:12,color:C.muted}}>📞 {a.clientPhone}</span>}
              </div>
              {addr&&<div style={{fontSize:12,color:C.muted,marginTop:2}}>📍 {addr}</div>}
              {a.notes&&<div style={{fontSize:12,color:C.muted,marginTop:3,fontStyle:"italic"}}>{a.notes}</div>}
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:6,alignItems:"flex-end"}}>
              <div style={row}>
                <button style={{...btn("blue"),padding:"6px 11px",fontSize:12}} onClick={()=>setPreview({html:buildApptDoc(a,clients),title:"OS – "+a.clientName})}><Icon d={IC.down} size={13}/>PDF</button>
                <button style={{background:"#25D366",border:"none",borderRadius:7,padding:"6px 11px",fontSize:12,fontWeight:700,color:"#fff",cursor:"pointer"}} onClick={()=>openWA(waText("AGENDAMENTO TÉCNICO",[`*Cliente:* ${a.clientName}`,a.clientPhone?`*Tel:* ${a.clientPhone}`:"",addr?`*End:* ${addr}`:"",a.date?`*Data:* ${new Date(a.date+"T12:00:00").toLocaleDateString("pt-BR")}`:"",a.time?`*Horário:* ${a.time}`:"",a.techName?`*Técnico:* ${a.techName}`:"",`*Status:* ${APST[a.status]?.label||a.status}`,a.serviceDesc?`\n*Serviço:* ${a.serviceDesc}`:"",a.notes?`*Obs:* ${a.notes}`:""].filter(Boolean)),a.clientPhone)}>📲</button>
                <button style={btn("ghost")} onClick={()=>setModal(a)}><Icon d={IC.edit} size={14}/></button>
                <button style={btn("danger")} onClick={()=>{if(window.confirm("Excluir?"))onDelete(a.id);}}><Icon d={IC.trash} size={14}/></button>
              </div>
              <select value={a.status} onChange={e=>onChange(a.id,{...a,status:e.target.value})} style={{...inp,width:"auto",fontSize:11,padding:"4px 8px"}}>
                {Object.entries(APST).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
              </select>
            </div>
          </div>;
        })}
      </div>}
    {modal!==null&&<ApptModal initial={modal==="new"?null:modal} clients={clients} tecnicos={tecnicos} onSave={item=>{onSave(item);setModal(null);flash("Salvo!");}} onClose={()=>setModal(null)}/>}
    {preview&&<DocPreview html={preview.html} title={preview.title} onClose={()=>setPreview(null)}/>}
  </div>;
}


// ═══════════════════════════════════════════════════════════════
// TAB: LAUDO TÉCNICO
// ═══════════════════════════════════════════════════════════════
const LDST = {pendente:{label:"Pendente",color:"#f39c12",bg:"rgba(243,156,18,0.15)"},aprovado:{label:"Aprovado",color:"#27ae60",bg:"rgba(39,174,96,0.15)"},reprovado:{label:"Reprovado",color:"#e74c3c",bg:"rgba(231,76,60,0.15)"},concluido:{label:"Concluído",color:"#2ecc71",bg:"rgba(46,204,113,0.15)"}};
function LBadge({status}){const s=LDST[status]||{label:status,color:"#888",bg:"rgba(128,128,128,0.1)"};return <span style={{background:s.bg,color:s.color,border:"1px solid "+s.color+"44",borderRadius:20,padding:"3px 12px",fontSize:11,fontWeight:700}}>{s.label}</span>;}

function LaudoModal({initial, clients, tecnicos, onSave, onClose}) {
  const [f, setF] = useState(initial?{...initial,photos:initial.photos||[],sigClient:initial.sigClient||""}:{id:"",clientId:"",clientName:"",clientPhone:"",clientAddress:"",clientCity:"",date:"",techName:"",equipment:"",serialNumber:"",problem:"",diagnosis:"",recommendation:"",result:"",status:"pendente",photos:[],notes:"",sigClient:""});
  const [cp, setCP] = useState(false);
  const [sigModal, setSigModal] = useState(false);
  const [photoErr, setPhotoErr] = useState("");
  const s = k=>e=>setF(p=>({...p,[k]:e.target.value}));
  const selC = c=>{setF(p=>({...p,clientId:c.id,clientName:c.name,clientPhone:c.phone||"",clientAddress:c.address||"",clientCity:c.city+(c.uf?"/"+c.uf:"")}));setCP(false);};
  const activeTec = (tecnicos||[]).filter(t=>t.active);

  const addPhotos = e=>{
    const files = Array.from(e.target.files);
    const rem = 8-f.photos.length;
    if (files.length>rem) setPhotoErr("Máximo 8 fotos."); else setPhotoErr("");
    files.slice(0,rem).forEach(file=>{const r=new FileReader();r.onload=ev=>setF(p=>({...p,photos:[...p.photos,{name:file.name,data:ev.target.result}]}));r.readAsDataURL(file);});
    e.target.value="";
  };

  const hasSig = f.sigClient && (f.sigClient.sigData || typeof f.sigClient==="string"&&f.sigClient.length>50);

  return <Modal title={f.id?"Editar Laudo":"Novo Laudo Técnico"} onClose={onClose} maxWidth={700}>
    {cp&&<ClientPicker clients={clients} onSelect={selC} onClose={()=>setCP(false)}/>}
    {sigModal&&<SignatureModal onSave={v=>{setF(p=>({...p,sigClient:v}));setSigModal(false);}} onClose={()=>setSigModal(false)} initNome={f.clientName}/>}
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Cliente</label>
        <div style={{display:"flex",gap:8}}><input style={{...inp,flex:1}} value={f.clientName} onChange={s("clientName")} placeholder="Nome"/>
          <button style={{...btn("blue"),padding:"9px 12px",flexShrink:0}} onClick={()=>setCP(true)}><Icon d={IC.users} size={14}/>Buscar</button></div></div>
      <div style={fld}><label style={lbl}>Telefone</label><input style={inp} value={f.clientPhone} onChange={s("clientPhone")}/></div>
      <div style={fld}><label style={lbl}>Data</label><input type="date" style={inp} value={f.date} onChange={s("date")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Endereço</label><input style={inp} value={f.clientAddress} onChange={s("clientAddress")} placeholder="Rua, nº, bairro"/></div>
      <div style={fld}><label style={lbl}>Cidade/UF</label><input style={inp} value={f.clientCity} onChange={s("clientCity")}/></div>
      <div style={fld}><label style={lbl}>Status</label>
        <select style={inp} value={f.status} onChange={s("status")}>{Object.entries(LDST).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}</select></div>
      <div style={fld}><label style={lbl}>Equipamento</label><input style={inp} value={f.equipment} onChange={s("equipment")} placeholder="Ex: Lavadora 14kg"/></div>
      <div style={fld}><label style={lbl}>Nº Série / Patrimônio</label><input style={inp} value={f.serialNumber} onChange={s("serialNumber")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Técnico</label>
        {activeTec.length>0
          ?<select style={inp} value={f.techName} onChange={s("techName")}>
              <option value="">— Selecionar —</option>
              {activeTec.map(t=><option key={t.id} value={t.name}>{t.name}{t.specialty?" · "+t.specialty:""}</option>)}
              <option value="__outro__">Outro…</option>
            </select>
          :<input style={inp} value={f.techName} onChange={s("techName")} placeholder="Nome do técnico"/>}
        {f.techName==="__outro__"&&<input style={{...inp,marginTop:8}} autoFocus placeholder="Nome do técnico" onChange={e=>setF(p=>({...p,techName:e.target.value}))}/>}
      </div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Problema Relatado</label><textarea rows={2} style={{...inp,resize:"vertical",minHeight:52}} value={f.problem} onChange={s("problem")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Diagnóstico</label><textarea rows={3} style={{...inp,resize:"vertical",minHeight:68}} value={f.diagnosis} onChange={s("diagnosis")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Recomendação</label><textarea rows={2} style={{...inp,resize:"vertical",minHeight:52}} value={f.recommendation} onChange={s("recommendation")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Resultado / Conclusão</label><textarea rows={2} style={{...inp,resize:"vertical",minHeight:52}} value={f.result} onChange={s("result")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}><label style={lbl}>Observações</label><textarea rows={2} style={{...inp,resize:"vertical",minHeight:48}} value={f.notes} onChange={s("notes")}/></div>
      <div style={{...fld,gridColumn:"1/-1"}}>
        <label style={lbl}>Fotos ({f.photos.length}/8)</label>
        <label style={{display:"flex",alignItems:"center",gap:8,padding:"9px 14px",background:C.navy,border:"2px dashed "+C.border,borderRadius:8,cursor:f.photos.length>=8?"not-allowed":"pointer",opacity:f.photos.length>=8?0.5:1,width:"fit-content"}}>
          <Icon d={IC.camera} size={16}/><span style={{fontSize:13,color:C.blueL}}>Adicionar fotos</span>
          <input type="file" accept="image/*" multiple style={{display:"none"}} disabled={f.photos.length>=8} onChange={addPhotos}/>
        </label>
        {photoErr&&<span style={{fontSize:12,color:"#e74c3c",marginTop:4}}>{photoErr}</span>}
        {f.photos.length>0&&<div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginTop:10}}>
          {f.photos.map((ph,i)=><div key={i} style={{position:"relative",borderRadius:8,overflow:"hidden",border:"1px solid "+C.border}}>
            <img src={ph.data} alt="" style={{width:"100%",height:88,objectFit:"cover",display:"block"}}/>
            <button onClick={()=>setF(p=>({...p,photos:p.photos.filter((_,j)=>j!==i)}))} style={{position:"absolute",top:4,right:4,background:"rgba(192,57,43,0.9)",border:"none",borderRadius:"50%",width:22,height:22,cursor:"pointer",color:"#fff",fontSize:12,fontWeight:700}}>✕</button>
          </div>)}
        </div>}
      </div>
      <div style={{...fld,gridColumn:"1/-1",borderTop:"1px solid "+C.border,paddingTop:16,marginTop:4}}>
        <div style={{fontSize:14,fontWeight:700,color:C.orange,marginBottom:12}}>✍️ Assinatura do Cliente</div>
        {hasSig
          ?<div style={{display:"flex",gap:12,alignItems:"flex-start",flexWrap:"wrap"}}>
              <div style={{flex:1,minWidth:180}}>
                {f.sigClient.sigNome&&<div style={{fontWeight:700,fontSize:13,marginBottom:4}}>{f.sigClient.sigNome}</div>}
                {f.sigClient.sigDoc&&<div style={{fontSize:12,color:C.blueL,marginBottom:6}}>Doc: {f.sigClient.sigDoc}</div>}
                <div style={{background:"#fff",borderRadius:8,border:"2px solid "+C.blue,padding:4}}>
                  <img src={f.sigClient.sigData||f.sigClient} alt="assinatura" style={{height:65,maxWidth:"100%",objectFit:"contain",display:"block"}}/>
                </div>
              </div>
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                <button onClick={()=>setSigModal(true)} style={{...btn("ghost"),padding:"8px 14px"}}>Refazer</button>
                <button onClick={()=>setF(p=>({...p,sigClient:""}))} style={{...btn("danger"),padding:"8px 14px"}}>Limpar</button>
              </div>
            </div>
          :<button onClick={()=>setSigModal(true)} style={{...btn("blue"),padding:"11px 22px",fontSize:14}}><Icon d={IC.edit} size={16}/>Abrir Área de Assinatura</button>}
      </div>
    </div>
    <div style={{...row,justifyContent:"flex-end",marginTop:18,gap:10}}>
      <button style={btn("ghost")} onClick={onClose}>Cancelar</button>
      <button style={btn("primary")} onClick={()=>{if(!f.clientName||!f.date){alert("Informe cliente e data.");return;}onSave({...f,id:f.id||uid()});}}><Icon d={IC.save} size={15}/>Salvar Laudo</button>
    </div>
  </Modal>;
}

function TabLaudo({clients, tecnicos, data, onSave, onDelete}) {
  const [modal, setModal] = useState(null);
  const [preview, setPreview] = useState(null);
  const [search, setSearch] = useState("");
  const [fs, setFS] = useState("todos");
  const [msg, setMsg] = useState(null);
  const flash = (t,tp="success")=>{setMsg({text:t,type:tp});setTimeout(()=>setMsg(null),3000);};

  const filtered = data.filter(l=>{
    const ms=fs==="todos"||l.status===fs;
    const q=search.toLowerCase();
    const mq=!q||[l.clientName,l.equipment,l.techName].some(v=>(v||"").toLowerCase().includes(q));
    return ms&&mq;
  }).sort((a,b)=>b.date>a.date?1:-1);

  const counts = data.reduce((acc,l)=>{acc[l.status]=(acc[l.status]||0)+1;return acc;},{});

  return <div><Alert msg={msg}/>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:18}}>
      {Object.entries(LDST).map(([k,v])=><div key={k} style={{background:C.navyM,border:"1px solid "+C.border,borderRadius:10,padding:"14px 18px",borderLeft:"3px solid "+v.color,cursor:"pointer",opacity:fs===k||fs==="todos"?1:0.5}} onClick={()=>setFS(fs===k?"todos":k)}>
        <div style={{fontSize:22,fontWeight:800,color:v.color}}>{counts[k]||0}</div>
        <div style={{fontSize:12,color:C.muted,marginTop:2}}>{v.label}</div>
      </div>)}
    </div>
    <div style={{...row,justifyContent:"space-between",marginBottom:14,flexWrap:"wrap",gap:10}}>
      <input placeholder="Buscar…" value={search} onChange={e=>setSearch(e.target.value)} style={{...inp,maxWidth:360}}/>
      <div style={row}>
        <select style={{...inp,width:"auto"}} value={fs} onChange={e=>setFS(e.target.value)}>
          <option value="todos">Todos</option>{Object.entries(LDST).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
        </select>
        <button style={btn("primary")} onClick={()=>setModal("new")}><Icon d={IC.plus} size={15}/>Novo Laudo</button>
      </div>
    </div>
    {filtered.length===0?<div style={{...card,textAlign:"center",padding:48,color:"#3a5880"}}>{data.length===0?"Nenhum laudo ainda.":"Sem resultados."}</div>
      :<div style={{display:"flex",flexDirection:"column",gap:12}}>
        {filtered.map(l=>{const d=l.date?new Date(l.date+"T12:00:00").toLocaleDateString("pt-BR"):"—";return <div key={l.id} style={{background:C.navyM,border:"1px solid "+C.border,borderRadius:12,padding:"16px 18px",borderLeft:"4px solid "+(LDST[l.status]?.color||C.border)}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",flexWrap:"wrap",gap:10}}>
            <div style={{flex:1}}>
              <div style={{...row,marginBottom:6,flexWrap:"wrap"}}>
                <span style={{fontWeight:800,fontSize:15}}>{l.clientName}</span><LBadge status={l.status}/>
                <span style={{fontSize:12,color:C.muted}}>📅 {d}</span>
              </div>
              {l.equipment&&<div style={{fontSize:13,color:C.blueL,marginBottom:3}}>⚙️ {l.equipment}{l.serialNumber?" · Série: "+l.serialNumber:""}</div>}
              {l.techName&&<div style={{fontSize:12,color:C.muted}}>👷 {l.techName}</div>}
              {l.clientAddress&&<div style={{fontSize:12,color:C.muted}}>📍 {l.clientAddress}</div>}
              {l.problem&&<div style={{fontSize:12,color:C.text,marginTop:6,fontStyle:"italic",borderLeft:"2px solid "+C.border,paddingLeft:8}}>{l.problem.slice(0,120)}{l.problem.length>120?"…":""}</div>}
              {l.photos&&l.photos.length>0&&<div style={{display:"flex",gap:6,marginTop:8,flexWrap:"wrap"}}>{l.photos.map((ph,i)=><img key={i} src={ph.data} alt="" style={{width:44,height:44,objectFit:"cover",borderRadius:6,border:"1px solid "+C.border}}/>)}</div>}
              {l.sigClient&&(l.sigClient.sigData||typeof l.sigClient==="string"&&l.sigClient.length>50)&&<div style={{fontSize:11,color:C.blueL,marginTop:6}}>✍️ {l.sigClient.sigNome?l.sigClient.sigNome+" — assinado":"Cliente assinado"}</div>}
            </div>
            <div style={{...row,flexShrink:0}}>
              <button style={{...btn("blue"),padding:"6px 11px",fontSize:12}} onClick={()=>setPreview({html:buildLaudoDoc(l),title:"Laudo – "+l.clientName})}><Icon d={IC.down} size={13}/>PDF</button>
              <button style={{background:"#25D366",border:"none",borderRadius:7,padding:"6px 11px",fontSize:12,fontWeight:700,color:"#fff",cursor:"pointer"}} onClick={()=>openWA(waText("LAUDO TÉCNICO",[`*Cliente:* ${l.clientName}`,l.clientPhone?`*Tel:* ${l.clientPhone}`:"",l.clientAddress?`*End:* ${l.clientAddress}`:"",l.date?`*Data:* ${d}`:"",l.techName?`*Técnico:* ${l.techName}`:"",l.equipment?`*Equipamento:* ${l.equipment}`:"",`*Status:* ${LDST[l.status]?.label||l.status}`,l.diagnosis?`\n*Diagnóstico:* ${l.diagnosis}`:"",l.result?`\n*Resultado:* ${l.result}`:"",l.sigClient&&l.sigClient.sigNome?`\n*Assinado por:* ${l.sigClient.sigNome}${l.sigClient.sigDoc?" ("+l.sigClient.sigDoc+")":""}`:""  ].filter(Boolean)),l.clientPhone)}>📲</button>
              <button style={btn("ghost")} onClick={()=>setModal(l)}><Icon d={IC.edit} size={14}/></button>
              <button style={btn("danger")} onClick={()=>{if(window.confirm("Excluir?"))onDelete(l.id);flash("Excluído.","error");}}><Icon d={IC.trash} size={14}/></button>
            </div>
          </div>
        </div>;})}
      </div>}
    {modal!==null&&<LaudoModal initial={modal==="new"?null:modal} clients={clients} tecnicos={tecnicos} onSave={item=>{onSave(item);setModal(null);flash("Laudo salvo!");}} onClose={()=>setModal(null)}/>}
    {preview&&<DocPreview html={preview.html} title={preview.title} onClose={()=>setPreview(null)}/>}
  </div>;
}


