function LoginOverlay({onLogin, onCancel}) {
  const [pw, setPw] = useState("");
  const [show, setShow] = useState(false);
  const [err, setErr] = useState("");

  const tryLogin = async () => {
    const stored = await load(K.password, DEFAULT_PW);
    if (pw === stored) { onLogin(); }
    else { setErr("Senha incorreta."); setPw(""); }
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.9)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:3000,fontFamily:"'Barlow',sans-serif"}}>
      <div style={{background:C.navyM,border:"1px solid "+C.border,borderRadius:16,padding:"40px 44px",width:"100%",maxWidth:380,textAlign:"center",position:"relative"}}>
        {onCancel&&<button onClick={onCancel} style={{position:"absolute",top:14,right:14,background:"none",border:"none",cursor:"pointer",color:C.muted}}><Icon d={IC.x} size={18}/></button>}
        <img src={LOGO} alt="Meca" style={{width:76,height:76,objectFit:"cover",borderRadius:12,marginBottom:18}}/>
        <div style={{fontSize:26,fontWeight:900,color:C.orange,letterSpacing:-1,marginBottom:4}}>meca</div>
        <div style={{fontSize:11,color:C.blueL,letterSpacing:3,textTransform:"uppercase",marginBottom:26}}>Laundry Solutions</div>
        <div style={{fontSize:13,color:C.muted,marginBottom:18}}>Digite a senha para acessar</div>
        {err&&<div style={{padding:"8px 14px",borderRadius:7,fontSize:13,fontWeight:600,marginBottom:14,background:"rgba(192,57,43,0.15)",color:"#e74c3c"}}>{err}</div>}
        <div style={{position:"relative",marginBottom:14}}>
          <input type={show?"text":"password"} placeholder="Senha" value={pw}
            onChange={e=>{setPw(e.target.value);setErr("");}}
            onKeyDown={e=>e.key==="Enter"&&tryLogin()}
            style={{...inp,paddingRight:44,fontSize:15,letterSpacing:2}} autoFocus/>
          <button onClick={()=>setShow(s=>!s)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:C.muted}}><Icon d={IC.eye} size={16}/></button>
        </div>
        <button style={{...btn("primary"),width:"100%",justifyContent:"center",padding:"12px",fontSize:15}} onClick={tryLogin}><Icon d={IC.lock} size={16}/>Entrar</button>
      </div>
    </div>
  );
}

function ChangePwModal({onClose}) {
  const [cur, setCur] = useState(""); const [nw, setNw] = useState(""); const [conf, setConf] = useState("");
  const [err, setErr] = useState(""); const [ok, setOk] = useState(false);
  const doSave = async () => {
    const stored = await load(K.password, DEFAULT_PW);
    if (cur!==stored){setErr("Senha atual incorreta.");return;}
    if (nw.length<6){setErr("Mínimo 6 caracteres.");return;}
    if (nw!==conf){setErr("Senhas não coincidem.");return;}
    await save(K.password, nw); setOk(true); setTimeout(onClose, 1500);
  };
  return <Modal title="Alterar Senha" onClose={onClose} maxWidth={400}>
    {ok?<div style={{textAlign:"center",padding:"20px 0",color:"#2ecc71",fontWeight:700}}>✓ Senha alterada!</div>
      :<div style={{display:"flex",flexDirection:"column",gap:14}}>
        {err&&<div style={{padding:"8px 14px",borderRadius:7,fontSize:13,fontWeight:600,background:"rgba(192,57,43,0.15)",color:"#e74c3c"}}>{err}</div>}
        <div style={fld}><label style={lbl}>Senha Atual</label><input type="password" style={inp} value={cur} onChange={e=>{setCur(e.target.value);setErr("");}}/></div>
        <div style={fld}><label style={lbl}>Nova Senha</label><input type="password" style={inp} value={nw} onChange={e=>{setNw(e.target.value);setErr("");}}/></div>
        <div style={fld}><label style={lbl}>Confirmar</label><input type="password" style={inp} value={conf} onChange={e=>{setConf(e.target.value);setErr("");}}/></div>
        <div style={{...row,justifyContent:"flex-end",gap:10}}>
          <button style={btn("ghost")} onClick={onClose}>Cancelar</button>
          <button style={btn("primary")} onClick={doSave}><Icon d={IC.key} size={15}/>Salvar</button>
        </div>
      </div>}
  </Modal>;
}

// ═══════════════════════════════════════════════════════════════
// ROOT APP — with auto-save on visibility change
// ═══════════════════════════════════════════════════════════════
function App() {
  const [authed, setAuthed]   = useState(false);
  const [showLogin, setLogin] = useState(false);
  const [changePw, setChangePw] = useState(false);
  const [tab, setTab]         = useState("laudo");
  const [loading, setLoading] = useState(true);

  // ── Shared data state ──────────────────────────────────────
  const [clients,  setClientsRaw]  = useState([]);
  const [services, setServicesRaw] = useState(SEED);
  const [quotes,   setQuotesRaw]   = useState([]);
  const [schedule, setScheduleRaw] = useState([]);
  const [laudos,   setLaudosRaw]   = useState([]);
  const [tecnicos, setTecnicosRaw] = useState([]);

  // ── Dirty flags — track unsaved changes ───────────────────
  const dirty = useRef({});

  function makeSetter(key, rawSetter) {
    return useCallback(val => {
      rawSetter(val);
      dirty.current[key] = val;
    }, []);
  }

  const setClients  = makeSetter(K.clients,  setClientsRaw);
  const setServices = makeSetter(K.services, setServicesRaw);
  const setQuotes   = makeSetter(K.quotes,   setQuotesRaw);
  const setSchedule = makeSetter(K.schedule, setScheduleRaw);
  const setLaudos   = makeSetter(K.laudos,   setLaudosRaw);
  const setTecnicos = makeSetter(K.tecnicos, setTecnicosRaw);

  // ── Flush dirty to shared storage ─────────────────────────
  const flush = useCallback(async () => {
    const d = dirty.current;
    dirty.current = {};
    await Promise.all(Object.entries(d).map(([k,v])=>save(k,v)));
  }, []);

  // ── Auto-save when tab goes to background ─────────────────
  useEffect(() => {
    const handler = () => {
      if (document.visibilityState === "hidden") flush();
    };
    document.addEventListener("visibilitychange", handler);
    return () => document.removeEventListener("visibilitychange", handler);
  }, [flush]);

  // ── Also save periodically (every 30s) ───────────────────
  useEffect(() => {
    const t = setInterval(flush, 30000);
    return () => clearInterval(t);
  }, [flush]);

  // ── Load all data on mount ─────────────────────────────────
  useEffect(() => {
    (async () => {
      const [cl,sv,qu,sc,ld,tc] = await Promise.all([
        load(K.clients,[]),  load(K.services,null),
        load(K.quotes,[]),   load(K.schedule,[]),
        load(K.laudos,[]),   load(K.tecnicos,[]),
      ]);
      setClientsRaw(cl||[]);
      setServicesRaw(sv&&sv.length>0?sv:SEED);
      if (!sv||!sv.length) await save(K.services,SEED);
      setQuotesRaw(qu||[]);
      setScheduleRaw(sc||[]);
      setLaudosRaw(ld||[]);
      setTecnicosRaw(tc||[]);
      setLoading(false);
    })();
    if (!document.getElementById("meca-font")) {
      const l = document.createElement("link");
      l.id="meca-font"; l.rel="stylesheet";
      l.href="https://fonts.googleapis.com/css2?family=Barlow:wght@400;600;700;800&family=Barlow+Condensed:wght@700;800&display=swap";
      document.head.appendChild(l);
    }
  }, []);

  // ── Generic CRUD helpers ───────────────────────────────────
  function upsert(list, setList, item) {
    const next = list.find(x=>x.id===item.id) ? list.map(x=>x.id===item.id?item:x) : [item,...list];
    setList(next);
  }
  function remove(list, setList, id) { setList(list.filter(x=>x.id!==id)); }

  // ── TABS ───────────────────────────────────────────────────
  const TABS = [
    {id:"laudo",     label:"Laudo Técnico",           icon:IC.camera,   free:true},
    {id:"agendamento",label:"Agendamento",             icon:IC.calendar, free:false},
    {id:"orcamento", label:"Orçamento",                icon:IC.quote,    free:false},
    {id:"servicos",  label:`Serviços (${services.length})`, icon:IC.wrench, free:false},
    {id:"clientes",  label:`Clientes (${clients.length})`,  icon:IC.users,  free:false},
    {id:"tecnicos",  label:`Técnicos (${tecnicos.length})`, icon:IC.user,   free:false},
  ];

  const goTab = t => { if (t.free||authed) setTab(t.id); else setLogin(true); };
  const onLogin = () => { setAuthed(true); setLogin(false); setTab("agendamento"); };

  if (loading) return (
    <div style={{minHeight:"100vh",background:C.navy,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:16,fontFamily:"'Barlow',sans-serif"}}>
      <img src={LOGO} alt="Meca" style={{width:76,height:76,objectFit:"cover",borderRadius:12}}/>
      <div style={{color:C.orange,fontWeight:700,fontSize:16}}>Carregando dados compartilhados…</div>
    </div>
  );

  return (
    <div style={{minHeight:"100vh",background:C.navy,fontFamily:"'Barlow',sans-serif",color:C.text}}>
      {showLogin&&<LoginOverlay onLogin={onLogin} onCancel={()=>setLogin(false)}/>}
      {changePw&&<ChangePwModal onClose={()=>setChangePw(false)}/>}

      {/* Header */}
      <div style={{background:"linear-gradient(135deg,#0f1f38,#0d1929)",borderBottom:"2px solid "+C.orange,padding:"0 20px",display:"flex",alignItems:"center",justifyContent:"space-between",height:62,boxShadow:"0 4px 24px rgba(0,0,0,0.4)"}}>
        <img src={LOGO} alt="Meca" style={{height:50,width:50,objectFit:"cover",borderRadius:8,flexShrink:0}}/>
        <div style={row}>
          {authed&&<button style={{...btn("ghost"),fontSize:12,padding:"6px 12px"}} onClick={()=>setChangePw(true)}><Icon d={IC.key} size={13}/>Alterar Senha</button>}
          {authed&&<button style={{...btn("ghost"),fontSize:12,padding:"6px 12px"}} onClick={async()=>{await flush();setAuthed(false);setTab("laudo");}}><Icon d={IC.lock} size={13}/>Sair</button>}
          {!authed&&<button style={{...btn("primary"),fontSize:12,padding:"6px 14px"}} onClick={()=>setLogin(true)}><Icon d={IC.lock} size={13}/>Entrar</button>}
        </div>
      </div>

      {/* Tabs */}
      <div style={{display:"flex",gap:4,padding:"14px 20px 0",borderBottom:"1px solid "+C.border,flexWrap:"wrap",overflowX:"auto"}}>
        {TABS.map(t=>{
          const active=tab===t.id, locked=!t.free&&!authed;
          return <button key={t.id} onClick={()=>goTab(t)}
            style={{display:"flex",alignItems:"center",gap:6,padding:"9px 16px",borderRadius:"8px 8px 0 0",
              border:"none",cursor:"pointer",fontSize:13,fontWeight:600,fontFamily:"inherit",
              background:active?C.orange:C.navyM,color:active?"#fff":locked?"#3a5275":C.muted,
              borderBottom:active?"2px solid "+C.orange:"2px solid transparent",opacity:locked?0.7:1,
              flexShrink:0}}>
            <Icon d={t.icon} size={14}/>{t.label}{locked&&<Icon d={IC.lock} size={11}/>}
          </button>;
        })}
      </div>

      {/* Content */}
      <div style={{padding:20,maxWidth:1100,margin:"0 auto"}}>
        {tab==="laudo"&&<TabLaudo clients={clients} tecnicos={tecnicos} data={laudos}
          onSave={l=>upsert(laudos,setLaudos,l)} onDelete={id=>remove(laudos,setLaudos,id)}/>}

        {tab==="agendamento"&&authed&&<TabAgendamento clients={clients} tecnicos={tecnicos} data={schedule}
          onSave={a=>upsert(schedule,setSchedule,a)} onDelete={id=>remove(schedule,setSchedule,id)}
          onChange={(id,a)=>setSchedule(schedule.map(x=>x.id===id?a:x))}/>}

        {tab==="orcamento"&&authed&&<TabOrcamento clients={clients} services={services} data={quotes}
          onSave={q=>setQuotes([q,...quotes.filter(x=>x.id!==q.id)])} onDelete={id=>remove(quotes,setQuotes,id)}/>}

        {tab==="servicos"&&authed&&<TabServicos data={services}
          onSave={s=>upsert(services,setServices,s)} onDelete={id=>remove(services,setServices,id)}/>}

        {tab==="clientes"&&authed&&<TabClientes data={clients}
          onSave={c=>upsert(clients,setClients,c)} onDelete={id=>remove(clients,setClients,id)}/>}

        {tab==="tecnicos"&&authed&&<TabTecnicos data={tecnicos}
          onSave={t=>upsert(tecnicos,setTecnicos,t)}
          onDelete={id=>remove(tecnicos,setTecnicos,id)}
          onToggle={id=>setTecnicos(tecnicos.map(t=>t.id===id?{...t,active:!t.active}:t))}/>}
      </div>
    </div>
  );
}
